(function(){
'use strict';
const $=(s,r=document)=>r.querySelector(s);
const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
const state={page:1,pageSize:20,search:'',animal_type:'',vaccinated:'',disease_status:'',status:'',sort:'household_code',direction:'ASC',catalogs:null,selectedHousehold:null,currentHouseholdId:null};
const API='/api/livestock';
function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));}
function num(v){return new Intl.NumberFormat('vi-VN').format(Number(v||0));}
function toast(msg,type='success'){ if(typeof showToast==='function') showToast(msg,type); else console[type==='danger'?'error':'log'](msg); }
function can(module,action){const role=(window.App?.user?.role||'').toUpperCase(); if(['SUPER_ADMIN','ADMIN'].includes(role))return true; if(role==='OFFICER')return module==='livestock'&&['read','create','update'].includes(action); if(role==='VIEWER')return module==='livestock'&&action==='read'; return true;}
async function request(url,options={}){ if(typeof api==='function')return api(url,options); const token=window.App?.token||localStorage.getItem('thon09_token')||''; const init={method:options.method||'GET',headers:{Accept:'application/json',Authorization:token?'Bearer '+token:''}}; if(options.body instanceof FormData)init.body=options.body; else if(options.body){init.headers['Content-Type']='application/json';init.body=JSON.stringify(options.body);} const res=await fetch(url,init); const json=await res.json().catch(()=>null); if(!res.ok||json?.ok===false)throw new Error(json?.error?.message||'Không tải được dữ liệu'); return json?.data??json;}
function debounce(fn,ms){let t;return function(){clearTimeout(t);t=setTimeout(()=>fn.apply(this,arguments),ms);};}
document.addEventListener('DOMContentLoaded',init);
document.addEventListener('thon09:screen-change',e=>{if(e.detail?.screen==='livestock')load();});
function init(){
const modal=$('#livestockModal'); if(modal&&window.bootstrap&&window.App?.modals) window.App.modals.livestock=new bootstrap.Modal(modal);
$('#livestockAddBtn')?.addEventListener('click',()=>openForm());
$('#livestockForm')?.addEventListener('submit',save);
$('#livestockSearch')?.addEventListener('input',debounce(()=>{state.search=$('#livestockSearch').value.trim();state.page=1;load();},300));
[['livestockAnimalTypeFilter','animal_type'],['livestockVaccinatedFilter','vaccinated'],['livestockDiseaseFilter','disease_status'],['livestockStatusFilter','status']].forEach(([id,key])=>$('#'+id)?.addEventListener('change',e=>{state[key]=e.target.value;state.page=1;load();}));
$('#livestockPageSize')?.addEventListener('change',e=>{state.pageSize=Number(e.target.value||20);state.page=1;load();});
$('#livestockFilterReset')?.addEventListener('click',resetFilters);
$('#livestockHouseholdAutocomplete')?.addEventListener('input',debounce(searchHouseholds,250));
document.addEventListener('click',event=>{if(!event.target.closest('#livestockHouseholdSuggestions')&&event.target.id!=='livestockHouseholdAutocomplete')hideSuggestions();});
$$('[data-livestock-sort]').forEach(th=>th.addEventListener('click',()=>sortBy(th.dataset.livestockSort)));
extendReports();
installHouseholdDetailHook();
if($('#livestockScreen')?.classList.contains('active'))load();
}
async function ensureCatalogs(){ if(state.catalogs)return state.catalogs; state.catalogs=await request(API+'/catalogs',{cacheTtl:60000}); fill('#livestockAnimalTypeSelect',state.catalogs.animal_types,'Chọn loại'); fill('#livestockAnimalTypeFilter',state.catalogs.animal_types,'Tất cả'); fill('#livestockDiseaseSelect',state.catalogs.disease_statuses,'Chọn tình trạng'); fill('#livestockDiseaseFilter',state.catalogs.disease_statuses,'Tất cả'); fill('#livestockStatusSelect',state.catalogs.statuses,'Chọn trạng thái'); return state.catalogs;}
function fill(sel,items,first){const el=$(sel); if(!el)return; el.innerHTML='<option value="">'+esc(first||'Chọn')+'</option>'+(items||[]).map(i=>'<option value="'+esc(i.value)+'">'+esc(i.label)+'</option>').join('');}
async function load(){ if(!can('livestock','read'))return; await ensureCatalogs(); const p=new URLSearchParams({page:state.page,pageSize:state.pageSize,sort:state.sort,direction:state.direction}); ['search','animal_type','vaccinated','disease_status','status'].forEach(k=>{if(state[k])p.set(k,state[k]);}); try{const data=await request(API+'?'+p.toString(),{cacheTtl:3000}); renderRows(data); renderPager(data); renderMiniDashboard();}catch(e){toast(e.message,'danger');}}
function renderRows(data){const host=$('#livestockRows'); if(!host)return; const items=data.items||[]; $('#livestockTotalCount')&&( $('#livestockTotalCount').textContent='Tổng số: '+num(data.total||0)+' bản ghi'); host.innerHTML=items.length?items.map((r,i)=>rowHtml(r,(data.page-1)*data.pageSize+i+1)).join(''):'<tr><td colspan="9" class="text-center text-muted py-4">Chưa có dữ liệu vật nuôi</td></tr>'; if(typeof window.thon09SyncResponsiveTableLabels==='function')window.thon09SyncResponsiveTableLabels($('#livestockScreen')||document);}
function rowHtml(r,idx){return '<tr><td data-label="STT">'+idx+'</td><td data-label="Mã hộ"><strong>'+esc(r.household_code)+'</strong><div class="text-muted small">'+esc(r.area_code||'')+'</div></td><td data-label="Chủ hộ">'+esc(r.head_citizen_name)+'</td><td data-label="Loại"><span class="badge text-bg-light">'+esc(r.animal_type)+'</span></td><td data-label="Giống">'+esc(r.breed||'Chưa cập nhật')+'</td><td data-label="Số lượng"><strong>'+num(r.quantity)+'</strong></td><td data-label="Tiêm phòng">'+(r.vaccinated?'<span class="badge text-bg-success">Đã tiêm</span>':'<span class="badge text-bg-warning">Chưa tiêm</span>')+'</td><td data-label="Trạng thái"><span class="badge text-bg-'+(r.status==='ACTIVE'?'success':'secondary')+'">'+esc(r.status_label)+'</span></td><td data-label="Thao tác" class="text-end"><div class="btn-group btn-group-sm"><button class="btn btn-outline-secondary" title="Xem hộ" onclick="window.showHousehold&&window.showHousehold('+Number(r.household_id)+')"><i class="fa-solid fa-eye"></i></button>'+(can('livestock','update')?'<button class="btn btn-outline-primary" title="Sửa" onclick="window.openLivestockForm('+Number(r.id)+')"><i class="fa-solid fa-pen-to-square"></i></button>':'')+(can('livestock','delete')?'<button class="btn btn-outline-danger" title="Xóa" onclick="window.deleteLivestock('+Number(r.id)+')"><i class="fa-solid fa-trash"></i></button>':'')+'</div></td></tr>';}
function renderPager(data){const host=$('#livestockPager'); if(!host)return; const page=Number(data.page||1),totalPages=Number(data.totalPages||1); const pages=[]; for(let i=Math.max(1,page-2);i<=Math.min(totalPages,page+2);i++)pages.push(i); host.innerHTML='<button class="btn btn-sm btn-outline-secondary" '+(page<=1?'disabled':'')+' data-page="'+(page-1)+'">Trước</button>'+pages.map(p=>'<button class="btn btn-sm '+(p===page?'btn-primary':'btn-outline-secondary')+'" data-page="'+p+'">'+p+'</button>').join('')+'<button class="btn btn-sm btn-outline-secondary" '+(page>=totalPages?'disabled':'')+' data-page="'+(page+1)+'">Sau</button>'; host.querySelectorAll('[data-page]').forEach(btn=>btn.addEventListener('click',()=>{state.page=Number(btn.dataset.page);load();}));}
async function renderMiniDashboard(){const host=$('#livestockMiniDashboard'); if(!host)return; try{const data=await request(API+'/dashboard',{cacheTtl:8000}); const m=data.metrics||{}; host.innerHTML=[['Hộ chăn nuôi',m.livestock_households,'hộ'],['Tổng vật nuôi',m.livestock_total,'con'],['Gia cầm',m.poultry_total,'con'],['Đã tiêm phòng',m.vaccinated_households,'hộ']].map(c=>'<article class="dashboard-kpi dashboard-tone-green"><div class="dashboard-kpi-head"><span class="dashboard-kpi-icon"><i class="fa-solid fa-paw"></i></span><span class="dashboard-kpi-label">'+esc(c[0])+'</span></div><div class="dashboard-kpi-value"><strong>'+num(c[1])+'</strong><span>'+esc(c[2])+'</span></div></article>').join('');}catch(e){host.innerHTML='';}}
function resetFilters(){Object.assign(state,{page:1,search:'',animal_type:'',vaccinated:'',disease_status:'',status:''}); ['livestockSearch','livestockAnimalTypeFilter','livestockVaccinatedFilter','livestockDiseaseFilter','livestockStatusFilter'].forEach(id=>{const el=$('#'+id);if(el)el.value='';}); load();}
function sortBy(key){if(state.sort===key)state.direction=state.direction==='ASC'?'DESC':'ASC';else{state.sort=key;state.direction='ASC';}load();}
async function openForm(id=null,household=null){ if(!can('livestock',id?'update':'create'))return toast('Tài khoản hiện tại không có quyền thực hiện thao tác này','warning'); await ensureCatalogs(); const form=$('#livestockForm'); if(!form)return; form.reset(); form.classList.remove('was-validated'); form.elements.id.value=''; form.elements.household_id.value=''; state.selectedHousehold=null; $('#livestockHouseholdAutocomplete').disabled=!!id||!!household; $('#livestockHouseholdAutocomplete').value=''; $('#livestockHouseholdSelected').textContent=''; hideSuggestions(); if(household)selectHousehold(household,true); if(id){const row=await request(API+'/'+encodeURIComponent(id)); setForm(row);} window.App?.modals?.livestock?.show();}
async function searchHouseholds(){const input=$('#livestockHouseholdAutocomplete'),host=$('#livestockHouseholdSuggestions'); if(!input||!host)return; const q=input.value.trim(); state.selectedHousehold=null; $('#livestockForm').elements.household_id.value=''; if(q.length<2){hideSuggestions();return;} const data=await request(API+'/household-search?q='+encodeURIComponent(q),{cacheTtl:3000}); const items=data.items||[]; host.innerHTML=items.length?items.map(item=>'<button type="button" class="list-group-item list-group-item-action" data-id="'+Number(item.id)+'"><div class="d-flex justify-content-between"><strong>'+esc(item.household_code)+'</strong><span class="badge text-bg-light">'+num(item.livestock_count)+' loại</span></div><div>'+esc(item.head_citizen_name||'')+'</div><small class="text-muted">'+esc(item.address||'')+'</small></button>').join(''):'<div class="list-group-item text-muted">Không tìm thấy hộ phù hợp</div>'; host.classList.remove('d-none'); host.querySelectorAll('[data-id]').forEach(btn=>btn.addEventListener('click',()=>selectHousehold(items.find(x=>String(x.id)===btn.dataset.id))));}
function selectHousehold(item,keepDisabled=false){if(!item)return; state.selectedHousehold=item; const form=$('#livestockForm'); form.elements.household_id.value=item.id; $('#livestockHouseholdAutocomplete').value=item.household_code+' - '+(item.head_citizen_name||''); $('#livestockHouseholdAutocomplete').disabled=keepDisabled||false; $('#livestockHouseholdSelected').textContent=item.address||''; hideSuggestions();}
function setForm(r){const form=$('#livestockForm'); selectHousehold({id:r.household_id,household_code:r.household_code,head_citizen_name:r.head_citizen_name,address:r.address},true); Object.entries({id:r.id,household_id:r.household_id,animal_type:r.animal_type,breed:r.breed,quantity:r.quantity,vaccinated:r.vaccinated?'1':'',vaccine_date:r.vaccine_date,disease_status:r.disease_status,barn_area:r.barn_area,status:r.status,note:r.note}).forEach(([k,v])=>{const el=form.elements[k]; if(!el)return; if(el.type==='checkbox')el.checked=!!v; else el.value=v??'';});}
async function save(e){e.preventDefault(); const form=e.currentTarget; const id=form.elements.id.value; if(!form.elements.household_id.value)return toast('Vui lòng chọn hộ gia đình','warning'); if(!form.checkValidity()){form.classList.add('was-validated');return;} const payload=Object.fromEntries(new FormData(form).entries()); payload.vaccinated=form.elements.vaccinated.checked?'1':'0'; delete payload.id; try{const saved=await request(id?API+'/'+encodeURIComponent(id):API,{method:id?'PUT':'POST',body:payload}); window.App?.modals?.livestock?.hide(); toast('Đã lưu vật nuôi'); load(); if(state.currentHouseholdId&&Number(saved.household_id)===state.currentHouseholdId)renderHouseholdLivestock(state.currentHouseholdId);}catch(err){toast(err.message,'danger');}}
async function remove(id){if(!can('livestock','delete'))return toast('Tài khoản hiện tại không có quyền xóa','warning'); if(!confirm('Xóa bản ghi vật nuôi này?'))return; try{const before=await request(API+'/'+encodeURIComponent(id)); await request(API+'/'+encodeURIComponent(id),{method:'DELETE'}); toast('Đã xóa vật nuôi'); load(); if(state.currentHouseholdId&&Number(before.household_id)===state.currentHouseholdId)renderHouseholdLivestock(state.currentHouseholdId);}catch(e){toast(e.message,'danger');}}
async function renderHouseholdLivestock(householdId){const host=$('#householdLivestockTabBody'); if(!host)return; state.currentHouseholdId=Number(householdId||0); try{const data=await request(API+'/household/'+encodeURIComponent(householdId),{cacheTtl:0}); const items=data.items||[]; host.innerHTML='<div class="d-flex justify-content-between align-items-center mb-2"><h6 class="mb-0">Vật nuôi</h6>'+(can('livestock','create')?'<button class="btn btn-sm btn-primary" type="button" id="householdLivestockAdd"><i class="fa-solid fa-plus"></i> Thêm vật nuôi</button>':'')+'</div>'+(items.length?'<div class="table-responsive"><table class="table table-sm align-middle mb-0"><thead><tr><th>Loại</th><th>Giống</th><th>Số lượng</th><th>Tiêm phòng</th><th class="text-end">Thao tác</th></tr></thead><tbody>'+items.map(r=>'<tr><td>'+esc(r.animal_type)+'</td><td>'+esc(r.breed||'')+'</td><td>'+num(r.quantity)+'</td><td>'+(r.vaccinated?'Đã tiêm':'Chưa tiêm')+'</td><td class="text-end"><button class="btn btn-sm btn-outline-primary" onclick="window.openLivestockForm('+Number(r.id)+')">Sửa</button> '+(can('livestock','delete')?'<button class="btn btn-sm btn-outline-danger" onclick="window.deleteLivestock('+Number(r.id)+')">Xóa</button>':'')+'</td></tr>').join('')+'</tbody></table></div>':'<div class="text-muted">Hộ này chưa có dữ liệu vật nuôi.</div>'); $('#householdLivestockAdd')?.addEventListener('click',()=>openForm(null,{id:householdId,household_code:$('#householdLivestockTabBody')?.dataset.code||'',head_citizen_name:$('#householdLivestockTabBody')?.dataset.head||'',address:$('#householdLivestockTabBody')?.dataset.address||''}));}catch(e){host.innerHTML='<div class="alert alert-danger mb-0">'+esc(e.message)+'</div>';}}
function installHouseholdDetailHook(){
if(typeof window.showHousehold!=='function'||window.showHousehold.__livestockHooked)return;
const original=window.showHousehold;
const wrapped=async function(id){
await original.apply(this,arguments);
const body=$('#detailBody');
if(!body||body.querySelector('#householdLivestockTabBody'))return;
let household={id};
try{household=await request('/api/households/'+encodeURIComponent(id),{cacheTtl:5000});}catch(e){}
const livestockSection=document.createElement('section');
livestockSection.className='content-card mt-3 household-livestock-section';
livestockSection.innerHTML='<div id="householdLivestockTabBody" data-code="'+esc(household.household_code||'')+'" data-head="'+esc(household.head_citizen_name||'')+'" data-address="'+esc(household.address||'')+'"><div class="text-muted">\u0110ang t\u1ea3i v\u1eadt nu\u00f4i...</div></div>';
const members=body.querySelector('.household-members-section');
if(members&&members.parentNode)members.parentNode.insertBefore(livestockSection,members);else body.appendChild(livestockSection);
renderHouseholdLivestock(id);
};
wrapped.__livestockHooked=true;
window.showHousehold=wrapped;
}
function extendReports(){const select=$('#reportType'); if(!select||select.querySelector('option[value="livestock"]'))return; [['livestock','Danh sách vật nuôi'],['livestock-by-type','Vật nuôi theo loại'],['livestock-vaccinated','Đã tiêm phòng'],['livestock-unvaccinated','Chưa tiêm phòng'],['livestock-disease','Có dịch bệnh vật nuôi']].forEach(([v,l])=>select.insertAdjacentHTML('beforeend','<option value="'+esc(v)+'">'+esc(l)+'</option>'));}
function hideSuggestions(){ $('#livestockHouseholdSuggestions')?.classList.add('d-none'); }
window.openLivestockForm=openForm; window.deleteLivestock=remove; window.renderHouseholdLivestock=renderHouseholdLivestock;
})();
